// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PostingBoard {
    struct Post {
        address author;
        string content;
        uint256 totalPower;
    }

    uint256 public postCount;
    mapping(uint256 => Post) private _posts;
    mapping(address => uint256) private _authorBalances;

    event PostCreated(uint256 indexed postId, address indexed author, string content);
    event PostBoosted(uint256 indexed postId, uint256 amount);
    event Withdrawn(address indexed author, uint256 amount);

    function posts(uint256 postId) public view returns (address author, string memory content, uint256 totalPower) {
        Post memory post = _posts[postId];
        return (post.author, post.content, post.totalPower);
    }

    function createPost(string calldata content) public returns (uint256) {
        require(bytes(content).length > 0, "Content cannot be empty");
        uint256 newPostId = postCount++;
        _posts[newPostId] = Post({
            author: msg.sender,
            content: content,
            totalPower: 0
        });
        emit PostCreated(newPostId, msg.sender, content);
        return newPostId;
    }

    function boostPost(uint256 postId) public payable {
        require(postCount > postId, "Post does not exist");
        require(msg.value > 0, "Value must be greater than 0");
        Post storage post = _posts[postId];
        require(post.author != address(0), "Post does not exist");

        post.totalPower += msg.value;
        _authorBalances[post.author] += msg.value;

        emit PostBoosted(postId, msg.value);
    }

    function authorBalances(address author) public view returns (uint256) {
        return _authorBalances[author];
    }

    function withdraw() public {
        uint256 balance = _authorBalances[msg.sender];
        require(balance > 0, "No funds to withdraw");
        _authorBalances[msg.sender] = 0;
        (bool sent, ) = payable(msg.sender).call{value: balance}("");
        require(sent, "Failed to send Ether");
        emit Withdrawn(msg.sender, balance);
    }
}
